const cats = [
  {category:'2',  name:'Сайты'},
  {category:'5',  name:'Программирование'},
  {category:'3',  name:'Дизайн'},
  {category:'8',  name:'Тексты'},
  {category:'32', name:'SMM'},
  {category:'41', name:'Автоматизация'},
  {category:'6',  name:'SEO'},
  {category:'12', name:'Реклама'},
];
return cats.map(c => ({ json: {
  url: 'https://www.fl.ru/rss/projects.xml?category=' + c.category,
  source: 'FL.ru / ' + c.name
}}));

return $input.all().map(i => {
  const j = i.json;
  const clean = (s) => ((s||'')+'').replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/&amp;/g,'&').replace(/\s+/g,' ').trim();
  return { json: {
    id: j.link || j.guid || j.id || j.title,
    title: clean(j.title),
    url: j.link || j.guid || '',
    snippet: clean(j.contentSnippet || j.content || j.description || '').slice(0,400),
    source: 'FL.ru',
    date: j.isoDate || j.pubDate || ''
  }};
});

const ch = ['frilanser_vacansii','Koteyka_Freelancer','textodromo','theyseeku','dnative_job','progjob','digitaltender','freelancetaverna','forktech','webfrl'];
return ch.map(c => ({ json: {
  url: 'https://t.me/s/' + c,
  source: '@' + c
}}));

const out = [];
for (const i of $input.all()) {
  const j = i.json;
  let html = '';
  for (const k of ['data','body','content','html']) { if (typeof j[k] === 'string' && j[k].length > html.length) html = j[k]; }
  if (!html && typeof j === 'string') html = j;
  const source = j.source || 'telegram';
  const re = /data-post="([^"]+)"[\s\S]*?js-message_text[^>]*>([\s\S]*?)<\/div>/g;
  let m;
  while ((m = re.exec(html))) {
    const id = m[1];
    const text = m[2].replace(/<br\/?>/g,' ').replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/&amp;/g,'&').replace(/&quot;/g,'"').replace(/\s+/g,' ').trim();
    if (text.length < 15) continue;
    out.push({ json: {
      id: 'tg/' + id,
      title: text.slice(0,90),
      url: 'https://t.me/' + id,
      snippet: text.slice(0,400),
      source: source,
      date: ''
    }});
  }
}
return out;

const KW = ['сайт','лендинг','landing','верстк','вёрстк','фронт','frontend','бэкенд','backend','tilda','тильда','wordpress','битрикс','bitrix','react','vue','html','css','javascript','веб','web','интернет-магазин','магазин','seo','api','парсер','парсинг','скрипт','автоматизац','интеграц','бот','чат-бот','чатбот','telegram','телеграм','n8n','make','zapier','нейросет','gpt','chatgpt','llm','openai','дизайн','логотип','баннер','макет','figma','фигма','иллюстрац','брендинг','фирменн','smm','смм','копирайт','текст','контент','reels','рилс','таргет','маркетолог'];

const store = $getWorkflowStaticData('global');
store.seen = store.seen || {};
const now = Date.now();

const build = (j) => {
  let t = '🆕 ' + j.source + '\n' + j.title;
  if (j.snippet && j.snippet !== j.title) t += '\n\n' + j.snippet;
  if (j.url) t += '\n\n' + j.url;
  return { json: { text: t } };
};

const cand = [];
for (const i of $input.all()) {
  const j = i.json;
  if (!j || !j.id) continue;
  const src = j.source || '';
  if (!src.startsWith('FL.ru')) {
    const hay = ((j.title||'') + ' ' + (j.snippet||'')).toLowerCase();
    if (!KW.some(k => hay.includes(k))) continue;
  }
  if (store.seen[j.id]) continue;
  cand.push(j);
}

const prune = () => {
  const keys = Object.keys(store.seen);
  if (keys.length > 5000) { keys.sort((a,b) => store.seen[a] - store.seen[b]); for (const k of keys.slice(0, keys.length - 3000)) delete store.seen[k]; }
};

const firstRun = Object.keys(store.seen).length === 0;

if (firstRun) {
  cand.forEach(j => { store.seen[j.id] = now; });
  prune();
  const sample = cand[0];
  if (!sample) return [];
  let t = '✅ Парсер заявок запущен. Слежу за биржей FL.ru и Telegram-каналами, дальше буду присылать только НОВЫЕ заявки.\n\nВот пример свежей заявки:\n\n🆕 ' + sample.source + '\n' + sample.title;
  if (sample.snippet && sample.snippet !== sample.title) t += '\n\n' + sample.snippet;
  if (sample.url) t += '\n\n' + sample.url;
  return [{ json: { text: t } }];
}

const MAX = 15;
const pick = cand.slice(0, MAX);
pick.forEach(j => { store.seen[j.id] = now; });
prune();
return pick.map(build);
